class Solution(object):
    def makeSmallestPalindrome(self, s):
        s = list(s)
        l, r = 0, len(s) - 1
        while l < r:
            m = min(s[l], s[r])
            s[l] = s[r] = m
            l += 1
            r -= 1
        return "".join(s)
